import { isArray, isUndefined } from 'lodash-es';

import { isFromTo, isSingleValue } from './type-guards.js';
import type { HeaderData, TooltipValue } from '../../../types.js';

export const getValue = (
  data?: HeaderData,
): TooltipValue | [TooltipValue, TooltipValue] | undefined => {
  if (isUndefined(data)) {
    return undefined;
  }
  if (isSingleValue(data)) {
    return isArray(data) ? data[0] : data;
  } else if (isFromTo(data)) {
    return data;
  }
};
